@@
 body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .local-layer-sandbox-strict {
 	--local-layer-l0-bg: var(--sky-color-background-page);
 	--local-layer-l1-bg: var(--sky-color-background-container-base);
 	--local-layer-l1-nested-bg: var(--sky-color-background-container-dimmed);
@@
 	--local-layer-link: var(--sky-color-text-action);
 	--local-layer-input-bg: var(--sky-color-background-container-dimmed);
 }
+
+/* Local layering demo override hooks. Update these in DevTools to test alternate layer behavior. */
+body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .local-layer-demo {
+	--local-layer-l0-bg: var(--local-layer-l0-bg, var(--sky-color-background-page));
+	--local-layer-l1-bg: var(--local-layer-l1-bg, var(--sky-color-background-container-base));
+	--local-layer-l1-nested-bg: var(--local-layer-l1-nested-bg, var(--sky-color-background-container-dimmed));
+	--local-layer-l2-bg: var(--local-layer-l2-bg, var(--sky-color-background-container-backdrop));
+	--local-layer-l3-bg: var(--local-layer-l3-bg, var(--sky-color-background-container-menu, var(--sky-color-background-container-backdrop)));
+	--local-layer-border: var(--local-layer-border, var(--sky-color-border-container-base));
+	--local-layer-divider: var(--local-layer-divider, var(--sky-color-border-divider));
+	--local-layer-input-bg: var(--local-layer-input-bg, var(--sky-color-background-container-dimmed));
+}
@@
 body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .local-layer-sandbox h1,
 body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .local-layer-sandbox h2,
