                 <header class="local-layer-controls" data-sky-layer="00">
                   <h1 class="local-layer-model-title">SKY UX Dark Surface Layering Sandbox</h1>
                   <p class="local-layer-model-copy">Static demo for inspecting background, border, divider, and field behavior across L0-L3.</p>
                   <p class="local-layer-model-copy">Experimental override hooks: <strong>--local-demo-l1-bg</strong>, <strong>--local-demo-l2-bg</strong>, <strong>--local-demo-l3-bg</strong>, <strong>--local-demo-border</strong>, <strong>--local-demo-divider</strong>, <strong>--local-demo-input-bg</strong>.</p>
+                  <div class="local-layer-mode-toggle">
+                    <strong>Layering mode</strong>
+                    <div class="local-layer-mode-tabs" role="tablist" aria-label="Layering mode" data-layering-mode-tabs>
+                      <button type="button" class="local-layer-mode-tab is-active" data-layering-mode="current" aria-pressed="true">Current SKY UX</button>
+                      <button type="button" class="local-layer-mode-tab" data-layering-mode="experimental" aria-pressed="false">Experimental</button>
+                    </div>
+                  </div>
                 </header>
@@
                 <section class="local-layer-surface local-layer-l3" data-sky-layer="03" aria-label="Layer 3 modal surface">
                   <span class="local-layer-chip">L3 Modal</span>
                   <h3>L3: Modal Surface</h3>
                   <p>Top-layer modal treatment for highest-priority surface testing.</p>
@@
                   <p><a href="#">Modal link</a></p>
                 </section>
               </main>`;
+
+            const setLayeringMode = (mode) => {
+              const nextMode = mode === 'experimental' ? 'experimental' : 'current';
+              document.body.dataset.layering = nextMode;
+
+              app.querySelectorAll('[data-layering-mode]').forEach((button) => {
+                const isActive = button.dataset.layeringMode === nextMode;
+                button.classList.toggle('is-active', isActive);
+                button.setAttribute('aria-pressed', String(isActive));
+              });
+            };
+
+            app.querySelector('[data-layering-mode-tabs]')?.addEventListener('click', (event) => {
+              const button = event.target.closest('[data-layering-mode]');
+
+              if (button instanceof HTMLButtonElement) {
+                setLayeringMode(button.dataset.layeringMode);
+              }
+            });
+
+            setLayeringMode(document.body.dataset.layering);
           }
         }
       } else {
*** End Patch"}

